//식당 검색 페이지

//api 연결
//선택된 태그들을 state(array)에 저장(가격은 따로 저장해야 될 듯)
//이걸 검색 페이지로 넘겨서 해당하는 식당들 보여줌 


"use client"
import { useState, useEffect, useRef } from 'react';
import type { Dispatch, SetStateAction } from 'react';
import { useRouter } from 'next/navigation';
import styles from './page.module.css';
import axios from 'axios';

import '@fortawesome/fontawesome-svg-core/styles.css';
import { config } from '@fortawesome/fontawesome-svg-core';
config.autoAddCss = false;
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome'
import { faChevronUp } from '@fortawesome/free-solid-svg-icons/faChevronUp';
import { faTrashCan } from '@fortawesome/free-regular-svg-icons';
import { faXmark } from '@fortawesome/free-solid-svg-icons';

export default function SearchPage() {

    const [query, setQuery] = useState('');
    const [suggestions, setSuggestions] = useState<string[]>([]);  
    const [isTagSearchOpen,setIsTagSearchOpen] = useState<boolean>(false)

    useEffect(()=>{document.body.style.overflow = 'hidden';},[])

    useEffect(() => {
        if (!query) {
            setSuggestions([]);
            return;
        }

        const timeoutId = setTimeout(() => {
            fetch(`/api/search-suggestions?q=${encodeURIComponent(query)}`)
                .then(res => res.json())
                .then(data => setSuggestions(data))
                .catch(err => console.error(err));
        }, 300); // 디바운스 300ms

        return () => clearTimeout(timeoutId);
    }, [query]);

    return (
        <main className={styles.nomrg}>
            <div>
                <br />
                <h1 className={styles.title} style={{ display: 'inline' }}>커카이브</h1>
                <p className={styles.sub_title} style={{ display: 'inline' }}>우리만의 미식 지도</p>
            </div>

            <div
                className = {styles.search_container}
                onClick={(e) => {
                    if (e.target === e.currentTarget) {
                        (document.activeElement as HTMLElement)?.blur();
                    }
                }}
            >

            <input className = {styles.input_box}
                type="text"
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                placeholder="식당 정보를 입력해주세요."
            />
            <button type="submit" className={styles.search_btn}></button>

            {suggestions.length > 0 && (
                <ul className={styles.suggestion_list}>
                    {suggestions.map((item, idx) => (
                        <li key={idx}>{item}</li>
                    ))}
                </ul>
            )}
            </div>
            
        
        <TagSearch isTagSearchOpen={isTagSearchOpen} setIsTagSearchOpen={setIsTagSearchOpen}/>
        </main>
    );
}

interface isTagSearchOpenType{
    isTagSearchOpen: boolean;
    setIsTagSearchOpen: React.Dispatch<React.SetStateAction<string>>
}

//태그로 검색하기 누르면 올라오는 Modal
function TagSearch({isTagSearchOpen,setIsTagSearchOpen}:isTagSearchOpenType){

    type SelectedItem = {
    type: 'region' | 'tag' | 'price';
    id: number | string; // 'price'는 id가 'price' 문자열
    name: string;      // 화면에 표시될 이름
    // (선택) 가격 범위는 여기에만 저장
    priceMin?: number; 
    priceMax?: number;
    };

    const tags:string[] = ["지역","음식 종류","가격","분위기"] // 상위 태그
    const [sellectedItems, setSellectedItems] = useState<SelectedItem[]>([]); //선택된 태그 한번에 관리
    const [activeTag,setActiveTag] = useState<string>("") //현재 클릭한 태그 저장
    const scrollRef = useRef<HTMLDivElement>(null)

    const router = useRouter(); //선택된 태그 정보들은 result 페이지로 넘기기 위한 라우터

    //router handler 이 함수를 '적용하기'에 적용
    const handleApply = () => {
        const params = new URLSearchParams();
        
        // 1. sellectedItems 배열을 순회하며 쿼리 파라미터 생성
        sellectedItems.forEach(item => {
            if (item.type === 'region') {
                params.append('region_id', item.id.toString());
            } 
            else if (item.type === 'tag') {
                params.append('tags_id', item.id.toString());
            } 
            else if (item.type === 'price') {
                params.append('price_min', item.priceMin.toString());
                params.append('price_max', item.priceMax.toString());
            }
        });

        router.push(`/restaurant_archive/search/result?${params.toString()}`);
    }

    //상위 태그 누르면 해당 위치로 이동하는 함수
    const handleScroll = () => {

        const content:HTMLDivElement = scrollRef.current

        if(activeTag == "지역"){
            content.scrollTo({
                    top: 0,
                    left: 0,
                    behavior: 'smooth'
            })
        }
        else if(activeTag == "음식 종류"){
            content.scrollTo({
                    top: 540,
                    left: 0,
                    behavior: 'smooth'
            })
        }
        else if(activeTag == "가격"){
            content.scrollTo({
                    top: 1070,
                    left: 0,
                    behavior: 'smooth'
            })
        }
        else if(activeTag == "분위기"){
            content.scrollTo({
                    top: 1630,
                    left: 0,
                    behavior: 'smooth'
            })
        }
    }

    // (수정) "아이템 추가" 함수 (Region, Food, Atmosphere에서 사용)
    const handleAddItem = (item: SelectedItem) => {
        // 중복 검사 (같은 타입과 ID를 가진 아이템이 이미 있는지)
        const isDuplicate = sellectedItems.some(
            existing => existing.type === item.type && existing.id === item.id
        );

        if (!isDuplicate) {
            setSellectedItems( (prevItems) => [...prevItems, item] );
        }
    }
    
    // (수정) "가격 추가" 함수 (Price 컴포넌트에서 사용)
    const handleAddPrice = (priceItem: SelectedItem) => {
        setSellectedItems( (prevItems) => {
            // 1. 기존에 'price' 타입이 있었다면 모두 제거
            const filteredItems = prevItems.filter(item => item.type !== 'price');
            // 2. 새 가격 아이템 추가
            return [...filteredItems, priceItem];
        });
    }

    // (수정) "아이템 삭제" 함수 (하단 바 X 버튼)
    const handleDeleteItem = (itemToDelete: SelectedItem) => {
        setSellectedItems( (prevItems) => 
            // 삭제할 아이템과 타입/ID가 다른 것들만 남김
            prevItems.filter(item => 
                !(item.type === itemToDelete.type && item.id === itemToDelete.id)
            )
        );
    }
    
    // (수정) "전부 삭제" 함수
    const deleteAll = () => {
        setSellectedItems([]); // 배열을 비우기만 하면 됨
    }

    useEffect(()=>(handleScroll()),[activeTag])

    return(
        <div className='tagSearch'>
            <div className={styles.tagSearch__chevron}>
                    <div><FontAwesomeIcon icon={faChevronUp}/></div>
                    <div><FontAwesomeIcon icon={faChevronUp}/></div>
                </div>
            <div className={`${styles.tagSearchContainer} ${isTagSearchOpen ? styles.show:null}`} >
                <h6 className={styles.tagSearch__title} onClick={()=>{
                    if(isTagSearchOpen == true){
                        setIsTagSearchOpen(false) 
                        console.log(isTagSearchOpen)}
                    else{setIsTagSearchOpen(true)
                        console.log(isTagSearchOpen)}}}>
                태그로 검색하기
                </h6>

            <div className={styles.tagSearch__tags}>
            {
                tags.map((a,i)=>{
                    return(
                     <div onClick={()=>{setActiveTag(a);}} className={`${styles.tagSearch__tag} ${activeTag == a ? styles.red : '' }`}>
                        <div>{a}</div>
                    </div>
            )})}
            </div>

        <div className={styles.tagSearch__bar}></div>

        <div ref={scrollRef} className={styles.scrollableContent}>
            <Region handleAddItem={handleAddItem}></Region>
            <Food handleAddItem={handleAddItem}></Food>
            <Price handleAddPrice={handleAddPrice}/>
            <Atmosphere handleAddItem={handleAddItem}/>
        </div>

        <div className={styles.tagSearch__bar}></div>
        <div className={styles.tagSearch__submit}>
            <div className={styles.tagSearch__iconAndTags}>
                <div className={styles.tagSearch__trashcan} onClick={deleteAll}><FontAwesomeIcon icon={faTrashCan} /></div>
                {
                    tagsToShow.map((tag)=>{
                        return(<div className={styles.tagSearch__selectedTag}>{tag}
                                    <span className={styles.tagSearch__tagDel} 
                                        onClick={()=>{handleDeleteTags(tag)
                                                      handleDeleteRegionId(tag)
                                        }}>
                                        <FontAwesomeIcon icon={faXmark} />
                                    </span>
                                </div>)})
                }
            </div>
            <div className={styles.tagSearch__submitBtns}>
                <button className={styles.tagSearch__apply} 
                onClick={handleApply}><span>적용하기</span></button>
                <button className={styles.tagSearch__close}>닫기</button>
            </div>
        </div>
        </div>
        </div>
    )
}

interface a{
    id: number;
    name: string;
    parent_id: string;
    depth: string;
}

interface RegionsType{
    handleAddItem: (item)=>{};
}

//상위 지역 Modal
function Region({handleAddItem}:RegionsType){

    const baseURL = process.env.REACT_APP_API_URL || 'http://152.69.228.114:8000';

    //상위 지역 저장
    const [higherRegions,setHigerRegions] = useState<[]>([]);

    //상위 지역 불러오는 함수
    const handleGetRigions = () => {
        axios.get(`${baseURL}/api/regions`)
        .then((res)=>{setHigerRegions(res.data)
                    console.log(res.data)})
    }

    //상위 지역 불러오기 
    useEffect(()=>{
        handleGetRigions()
        console.log(higerRegions);
    },[])

    const [showSpecificRegions,setShowSpecificRegions] = useState(false)
    const [regionName,setRegionName] = useState<string>("")

    return(
    <div className={styles.tagSearch__body}>
            <div className={styles.tagSearch__regions}>
            {
                higherRegions.map((a)=>{
                    return(
                        <span onClick={()=>{
                        setRegionName(a.name)
                        setShowSpecificRegions(true)
                        }} 
                        className={`${regionName == a.name ? styles.redBorder : ''}`}>
                        {a.name}</span>
                    )})
            }  
            </div>
        {showSpecificRegions && <SpecificRegion regionName={regionName} handleAddItem={handleAddItem}/>}
    
        
        </div>)
}

interface SpecificRegionsType{
    regionName:string;
    handleAddItem: (item)=>{};
}

//상세 지역 modal
function SpecificRegion({regionName,handleAddItem}:SpecificRegionsType){ 

    //axios 호출할 때 주소 앞에 baseURL 붙여야 함
    const baseURL = process.env.REACT_APP_API_URL || 'http://152.69.228.114:8000';

    const [region,setRegion] = useState([]) 
    const regions = {서울:1,경기:2,인천:3,부산:4,강원:5,대전:6,충북:7,충남:8,경남:9,대구:10,경북:11,울산:12,전남:13,광주:14,전북:15,제주:16,세종:18}

    //하위 지역 불러오기
    const getSpecificRegion = () => {
    axios.get(`${baseURL}/api/regions?parent_id=${regions[regionName]}`)
                .then((res)=>{setRegion(res.data)
                console.log(res.data)
                })
    }
    
    useEffect(()=>{
        getSpecificRegion()
    },[regionName])

    if (region != null){     
        return (
            <div className={styles.specificRegions}>
                {region.map((reg) => (
                    <div key={reg.id} onClick={()=>{
                        handleAddItem({type: 'region', id: reg.id, name: reg.name})
                       }}>{reg.name}</div>
                ))}
            </div>
        );
    }
    else{
        return (<div className={styles.specificRegions}>로딩중</div>)
    }       
}

