//음식 종류 modal
function Food(handleAddItem:FoodType){
    const baseURL = process.env.REACT_APP_API_URL || 'http://152.69.228.114:8000';
    const [tags,setTags] = useState<tagsType[]>([])

    useEffect(()=>{
        axios.get(`${baseURL}/api/tags`)
        .then((res)=>(setTags(tags.concat(res.data))))
    },[])
    

    const cultureTags:string[][] = [["한식","중식","일식","양식"],["인도","동남아시아","중동","아프리카"],["양식","북미","남미","북유럽"],["동유럽","컨템포러리(퓨전)"]]
    const foodTags:string[] = ["고기","해산물","채소","디저트","음료","밥류","국물류/스튜류","면류","빵류"]

    return(
        <div className={styles.Food__container}>
            <img className={styles.Food__mapImg} src="../images/지도.png"/>
            <div className={styles.Food__tagContainer}>
            {
                cultureTags.map((tags)=>{
                    return(
                    <div>
                        {tags.map((tag)=>{
                            return(
                                <span className={styles.Food__tag} 
                                onClick={()=>{handleAddItem()}}>
                                {tag}</span>
                            )})}
                    </div>)})
            }
            </div>
            <div className={styles.Food__foodTags}>
                {
                    foodTags.map((tag)=>{
                        return(
                        <div onClick={()=>{handleAddItem(tag)}}>{tag}</div>
                        )
                    })
                }
            </div>
        </div>
            

        
    )
}

//Price 모듈에서 tagSearch로 min price, max price 보내기 위한 타입 선언
interface PriceLimitType{
    sellectedTags: {};
    setSellectedTags: React.Dispatch<React.SetStateAction<{}>>;
    setTagsToShow: React.Dispatch<React.SetStateAction<[]>>;
    tagsToShow: string[];
}

//가격 Modal
